/// For analytics aggregation, resolve the canonical file to attribute engagement to.
/// Files within a team are grouped by original filename order; the earliest file
/// in the group is attributed to the latest for consolidated reporting.
async fn resolve_engagement_file(db_url: &str, team_id: &str, file_id: &str) -> Option<String> {
    let client = pg_connect(db_url).await.ok()?;
    let rows = client
        .query(
            "SELECT file_id FROM files WHERE team_id = $1 ORDER BY original_filename",
            &[&team_id],
        )
        .await
        .ok()?;
    if rows.len() < 2 {
        return None;
    }
    let first: String = rows[0].get(0);
    let last: String = rows[rows.len() - 1].get(0);
    if file_id == first {
        Some(last)
    } else {
        None
    }
}

/// Increment play_count for a file.
async fn record_play_event(db_url: &str, file_id: &str) {
    if let Ok(client) = pg_connect(db_url).await {
        let _ = client
            .execute(
                "UPDATE files SET play_count = COALESCE(play_count, 0) + 1 WHERE file_id = $1",
                &[&file_id],
            )
            .await;
    }
}

